# Based on Gilks, W. R., & Wild, P. (1992). Adaptive rejection sampling for Gibbs sampling.
# Journal of the Royal Statistical Society: Series C (Applied Statistics), 41(2), 337-348.

# Main ARS function
ars <- function(n, f, domain = c(-Inf, Inf), initial_points = NULL, ...) {
  # Input validation
  if (!is.numeric(n) || n <= 0 || n != floor(n)) {
    stop("Number of samples must be a positive integer")
  }

  if (!is.function(f)) {
    stop("Density function must be a function")
  }

  if (!is.numeric(domain) || length(domain) != 2 || domain[1] >= domain[2]) {
    stop("Domain must be a numeric vector of length 2 with domain[1] < domain[2]")
  }

  # Set default initial points if not provided
  if (is.null(initial_points)) {
    # For finite domain, use endpoints; otherwise use some default values
    if (is.finite(domain[1]) && is.finite(domain[2])) {
      initial_points <- c(domain[1], domain[2])
    } else {
      initial_points <- c(-1, 0, 1)
      # Adjust if outside domain
      if (!is.finite(domain[1])) {
        initial_points[1] <- -2
      } else {
        initial_points[1] <- domain[1] + (initial_points[2] - domain[1]) / 3
      }

      if (!is.finite(domain[2])) {
        initial_points[3] <- 2
      } else {
        initial_points[3] <- domain[2] - (domain[2] - initial_points[2]) / 3
      }
    }
  }

  # Validate initial points
  if (!is.numeric(initial_points) || length(initial_points) < 2) {
    stop("Initial points must be a numeric vector with at least 2 elements")
  }

  # Check if initial points are within domain
  if (any(initial_points <= domain[1]) || any(initial_points >= domain[2])) {
    stop("All initial points must be within the specified domain")
  }

  # Sort initial points
  initial_points <- sort(unique(initial_points))

  # Evaluate log-density at initial points
  log_f_vals <- tryCatch({
    sapply(initial_points, function(x) log(f(x, ...)))
  }, error = function(e) {
    stop("Error evaluating density function: ", e$message)
  })

  # Check for non-finite values
  if (any(!is.finite(log_f_vals))) {
    stop("Density function evaluates to non-finite values at initial points")
  }

  # Check log-concavity at initial points
  if (length(initial_points) >= 3) {
    for (i in 2:(length(initial_points)-1)) {
      x1 <- initial_points[i-1]
      x2 <- initial_points[i]
      x3 <- initial_points[i+1]
      y1 <- log_f_vals[i-1]
      y2 <- log_f_vals[i]
      y3 <- log_f_vals[i+1]

      # Check if the middle point is below the line connecting the other two
      slope <- (y3 - y1) / (x3 - x1)
      pred_y2 <- y1 + slope * (x2 - x1)

      if (y2 > pred_y2 + 1e-10) {  # Small tolerance for numerical errors
        stop("Density function is not log-concave at initial points")
      }
    }
  }

  # Initialize hull points and values
  hull_points <- initial_points
  log_hull_vals <- log_f_vals

  # Calculate piecewise linear hull
  hull_segments <- calculate_hull_segments(hull_points, log_hull_vals)

  # Sample generation
  samples <- numeric(n)
  i <- 1

  while (i <= n) {
    # Sample from the upper hull
    x_candidate <- sample_from_upper_hull(hull_segments, domain)

    # Evaluate log density at candidate
    log_f_candidate <- tryCatch({
      log(f(x_candidate, ...))
    }, error = function(e) {
      warning("Error evaluating density function at candidate point: ", e$message)
      return(-Inf)
    })

    if (!is.finite(log_f_candidate)) {
      # Add point to improve hull
      hull_points <- append_and_sort(hull_points, x_candidate)
      log_hull_vals <- c(log_hull_vals, log_f_candidate)
      hull_segments <- calculate_hull_segments(hull_points, log_hull_vals)
      next
    }

    # Evaluate upper hull at candidate
    log_hull_candidate <- evaluate_upper_hull(x_candidate, hull_segments)

    # Acceptance probability
    log_accept_prob <- log_f_candidate - log_hull_candidate

    # Accept or reject
    if (log_accept_prob >= 0 || log(runif(1)) < log_accept_prob) {
      samples[i] <- x_candidate
      i <- i + 1
    }

    # Update hull with new point
    hull_points <- append_and_sort(hull_points, x_candidate)
    log_hull_vals <- c(log_hull_vals, log_f_candidate)
    hull_segments <- calculate_hull_segments(hull_points, log_hull_vals)

    # Check log-concavity with new point
    idx <- which(hull_points == x_candidate)
    if (idx > 1 && idx < length(hull_points)) {
      x1 <- hull_points[idx-1]
      x2 <- hull_points[idx]
      x3 <- hull_points[idx+1]
      y1 <- log_hull_vals[idx-1]
      y2 <- log_hull_vals[idx]
      y3 <- log_hull_vals[idx+1]

      # Check if the new point violates log-concavity
      slope <- (y3 - y1) / (x3 - x1)
      pred_y2 <- y1 + slope * (x2 - x1)

      if (y2 > pred_y2 + 1e-10) {  # Small tolerance
        stop("Density function is not log-concave at sampled point")
      }
    }
  }

  return(samples)
}

# Helper function to calculate hull segments
calculate_hull_segments <- function(points, vals) {
  if (length(points) < 2) {
    stop("Need at least 2 points to define hull segments")
  }

  segments <- list()
  for (i in 1:(length(points)-1)) {
    x1 <- points[i]
    x2 <- points[i+1]
    y1 <- vals[i]
    y2 <- vals[i+1]

    # Line equation: y = slope * (x - x1) + y1
    slope <- (y2 - y1) / (x2 - x1)

    segments[[i]] <- list(x1 = x1, x2 = x2, y1 = y1, slope = slope)
  }

  return(segments)
}

# Helper function to sample from upper hull
sample_from_upper_hull <- function(segments, domain) {
  if (length(segments) == 0) {
    stop("No segments in hull")
  }

  # Calculate areas under each segment (exponentiated)
  areas <- numeric(length(segments))
  total_area <- 0

  for (i in 1:length(segments)) {
    seg <- segments[[i]]
    # For a line y = slope*(x-x1) + y1, the integral from x1 to x2 is:
    # (y1+y2)/2 * (x2-x1) = (2*y1 + slope*(x2-x1))/2 * (x2-x1)
    # But we're working in log space, so we need to exponentiate

    # Compute the integral of exp(slope*(x-x1) + y1) from x1 to x2
    # This is exp(y1) * (exp(slope*(x2-x1)) - 1) / slope if slope != 0
    # Or exp(y1) * (x2-x1) if slope == 0

    dx <- seg$x2 - seg$x1
    if (abs(seg$slope) < 1e-12) {
      # Nearly horizontal line
      areas[i] <- exp(seg$y1) * dx
    } else {
      areas[i] <- exp(seg$y1) * (exp(seg$slope * dx) - 1) / seg$slope
    }

    # Ensure area is positive (can be negative if slope is negative and large)
    areas[i] <- max(areas[i], 0)
    total_area <- total_area + areas[i]
  }

  # Sample a segment according to its area
  u <- runif(1) * total_area
  cum_area <- 0
  selected_seg_idx <- 1

  for (i in 1:length(segments)) {
    cum_area <- cum_area + areas[i]
    if (u <= cum_area) {
      selected_seg_idx <- i
      break
    }
  }

  # Sample from the selected segment
  seg <- segments[[selected_seg_idx]]

  # For a line y = slope*(x-x1) + y1, the cumulative distribution function is:
  # CDF(x) = integral from x1 to x of exp(slope*(t-x1) + y1) dt
  #        = exp(y1) * (exp(slope*(x-x1)) - 1) / slope if slope != 0
  #        = exp(y1) * (x-x1) if slope == 0

  # To sample, we invert the CDF:
  # u * total_area_segment = exp(y1) * (exp(slope*(x-x1)) - 1) / slope
  # Solve for x

  u_seg <- runif(1)
  dx <- seg$x2 - seg$x1

  if (abs(seg$slope) < 1e-12) {
    # Nearly horizontal line
    x_sample <- seg$x1 + u_seg * dx
  } else {
    # Exponential case
    exp_y1 <- exp(seg$y1)
    area_seg <- exp_y1 * (exp(seg$slope * dx) - 1) / seg$slope
    u_scaled <- u_seg * area_seg

    # u_scaled = exp_y1 * (exp(seg$slope*(x-seg$x1)) - 1) / seg$slope
    # u_scaled * seg$slope / exp_y1 = exp(seg$slope*(x-seg$x1)) - 1
    # exp(seg$slope*(x-seg$x1)) = u_scaled * seg$slope / exp_y1 + 1
    # seg$slope*(x-seg$x1) = log(u_scaled * seg$slope / exp_y1 + 1)
    # x = seg$x1 + log(u_scaled * seg$slope / exp_y1 + 1) / seg$slope

    temp <- u_scaled * seg$slope / exp_y1 + 1
    if (temp <= 0) {
      # Numerical issue, fallback to uniform sampling
      x_sample <- seg$x1 + u_seg * dx
    } else {
      x_sample <- seg$x1 + log(temp) / seg$slope
    }
  }

  return(x_sample)
}

# Helper function to evaluate upper hull at a point
evaluate_upper_hull <- function(x, segments) {
  # Find the segment that contains x
  seg_idx <- NA
  for (i in 1:length(segments)) {
    if (x >= segments[[i]]$x1 && x <= segments[[i]]$x2) {
      seg_idx <- i
      break
    }
  }

  # If x is outside all segments, extrapolate from nearest segment
  if (is.na(seg_idx)) {
    if (x < segments[[1]]$x1) {
      seg_idx <- 1
    } else {
      seg_idx <- length(segments)
    }
  }

  seg <- segments[[seg_idx]]

  # Evaluate the linear function
  y <- seg$slope * (x - seg$x1) + seg$y1

  return(y)
}

# Helper function to append a point and keep sorted
append_and_sort <- function(points, new_point) {
  points <- c(points, new_point)
  return(sort(unique(points)))
}

# Test function
test <- function() {
  cat("Running tests for Adaptive Rejection Sampler...\n\n")

  # Test 1: Standard normal distribution
  cat("Test 1: Standard Normal Distribution\n")
  tryCatch({
    # Define standard normal density (unnormalized)
    dnorm_unnorm <- function(x) exp(-0.5 * x^2)

    # Generate samples
    set.seed(123)  # For reproducibility
    samples <- ars(1000, dnorm_unnorm)

    # Calculate sample statistics
    sample_mean <- mean(samples)
    sample_sd <- sd(samples)

    # Theoretical values for standard normal
    true_mean <- 0
    true_sd <- 1

    # Check if sample statistics are close to theoretical values
    mean_diff <- abs(sample_mean - true_mean)
    sd_diff <- abs(sample_sd - true_sd)

    # Tolerance for comparison (allowing for sampling variability)
    tol <- 0.1

    if (mean_diff <= tol && sd_diff <= tol) {
      cat(sprintf("NORMAL_TEST: PASS (mean=%.3f, sd=%.3f)\n\n", sample_mean, sample_sd))
    } else {
      cat(sprintf("NORMAL_TEST: FAIL (mean=%.3f, sd=%.3f)\n\n", sample_mean, sample_sd))
    }

    # Save samples to file
    write.table(samples, file="/app/normal_samples.txt", row.names=FALSE, col.names=FALSE)
  }, error = function(e) {
    cat(sprintf("NORMAL_TEST: ERROR - %s\n\n", e$message))
  })

  # Test 2: Exponential distribution
  cat("Test 2: Exponential Distribution\n")
  tryCatch({
    # Define exponential density (rate=1)
    dexp_unnorm <- function(x) ifelse(x >= 0, exp(-x), 0)

    # Generate samples
    set.seed(456)  # For reproducibility
    samples <- ars(1000, dexp_unnorm, domain=c(0, Inf))

    # Calculate sample statistics
    sample_mean <- mean(samples)
    sample_sd <- sd(samples)

    # Theoretical values for exponential(rate=1)
    true_mean <- 1
    true_sd <- 1

    # Check if sample statistics are close to theoretical values
    mean_diff <- abs(sample_mean - true_mean)
    sd_diff <- abs(sample_sd - true_sd)

    # Tolerance for comparison (allowing for sampling variability)
    tol <- 0.1

    if (mean_diff <= tol && sd_diff <= tol) {
      cat(sprintf("EXPONENTIAL_TEST: PASS (mean=%.3f, sd=%.3f)\n\n", sample_mean, sample_sd))
    } else {
      cat(sprintf("EXPONENTIAL_TEST: FAIL (mean=%.3f, sd=%.3f)\n\n", sample_mean, sample_sd))
    }

    # Save samples to file
    write.table(samples, file="/app/exponential_samples.txt", row.names=FALSE, col.names=FALSE)
  }, error = function(e) {
    cat(sprintf("EXPONENTIAL_TEST: ERROR - %s\n\n", e$message))
  })

  # Test 3: Invalid inputs
  cat("Test 3: Input Validation\n")
  tryCatch({
    # Try with negative sample count
    ars(-5, function(x) exp(-0.5 * x^2))
    cat("INPUT_VALIDATION_TEST: FAIL - Should have rejected negative sample count\n\n")
  }, error = function(e) {
    if (grepl("positive integer", e$message)) {
      cat("INPUT_VALIDATION_TEST: PASS\n\n")
    } else {
      cat(sprintf("INPUT_VALIDATION_TEST: FAIL - Unexpected error: %s\n\n", e$message))
    }
  })

  # Test 4: Non-log-concave density
  cat("Test 4: Log-Concavity Check\n")
  tryCatch({
    # Define a non-log-concave density (bimodal)
    dbimodal <- function(x) exp(-((x-2)^4/4 - (x-2)^2))

    # Try to sample from it
    samples <- ars(100, dbimodal)
    cat("LOG_CONCAVITY_TEST: FAIL - Should have detected non-log-concave density\n\n")
  }, error = function(e) {
    if (grepl("log-concave", e$message)) {
      cat("LOG_CONCAVITY_TEST: PASS\n\n")
    } else {
      cat(sprintf("LOG_CONCAVITY_TEST: FAIL - Unexpected error: %s\n\n", e$message))
    }
  })

  cat("Tests completed.\n")
}

